const body = $input.first().json.body || $input.first().json;
const title = body.title || '';
const primary = (body.primary_keywords || []).join(' ');
const secondary = (body.secondary_keywords || []).slice(0, 5).join(' ');
const audience = (body.target_audience || '').slice(0, 80);
const year = new Date().getFullYear();
const searchQuery = [
  title,
  primary,
  secondary,
  audience,
  String(year),
  'case study statistics ROI market trends companies tools deployment',
]
  .filter(Boolean)
  .join(' ')
  .trim()
  .replace(/\s+/g, ' ');

const lengthTargets = { short: 500, medium: 1000, long: 2000 };
const targetWords = lengthTargets[body.length] || 1000;

return [{
  json: {
    ...body,
    search_query: searchQuery,
    target_words: targetWords,
  },
}];

const input = $('Build Search Query').first().json;
const tavily = $input.first().json;
const results = (tavily.results || []).slice(0, 4);
const sources = results.map(r => r.url).filter(Boolean);
const limit = (text, max = 700) => String(text || '').replace(/\s+/g, ' ').trim().slice(0, max);

let context = '';
if (tavily.answer) {
  context += `Summary: ${limit(tavily.answer, 900)}\n\n`;
}
results.forEach((r, i) => {
  context += `Source ${i + 1}: ${limit(r.title, 120)}\nURL: ${r.url}\n${limit(r.content)}\n\n`;
});

if (!context.trim()) {
  context = 'No web results found. Use general knowledge but note limited recent data.';
}

return [{
  json: {
    ...input,
    research_context: context,
    sources
  }
}];

const groq = $input.first().json;
const meta = $('Format Research').first().json;

let blog = '';
try {
  blog = groq.choices[0].message.content;
} catch (e) {
  throw new Error('Failed to parse Groq response: ' + JSON.stringify(groq));
}

blog = blog.trim();
if (blog.startsWith('```')) {
  blog = blog.replace(/^```(?:markdown)?\n?/, '').replace(/\n?```$/, '');
}

const word_count = blog.split(/\s+/).filter(Boolean).length;

return [{
  json: {
    blog,
    word_count,
    sources: meta.sources || []
  }
}];
